const inputData = $input.first().json;
const language = inputData['Preferred Language'] || 'English';
const translations = {
  'English': { subject: 'Tailored Proposal & Invoice', greeting: 'Dear', summary: 'Thank you for your interest in our services. We have prepared a tailored proposal for you.', attached: 'Please find the following documents attached:', pLabel: 'Detailed Proposal', iLabel: 'Invoice' },
  'Tamil': { subject: 'தனிப்பயனாக்கப்பட்ட முன்மொழிவு மற்றும் விலைப்பட்டியல்', greeting: 'அன்புள்ள', summary: 'எங்கள் சேவைகளில் நீங்கள் காட்டிய ஆர்வத்திற்கு நன்றி. உங்களுக்காக ஒரு பிரத்யேக முன்மொழிவைத் தயாரித்துள்ளோம்.', attached: 'பின்வரும் ஆவணங்கள் இணைக்கப்பட்டுள்ளன:', pLabel: 'விரிவான முன்மொழிவு', iLabel: 'விலைப்பட்டியல்' },
  'Hindi': { subject: 'अनुकूलित प्रस्ताव और चालान', greeting: 'प्रिय', summary: 'हमारी सेवाओं में आपकी रुचि के लिए धन्यवाद। हमने आपके लिए एक विशेष प्रस्ताव तैयार किया है।', attached: 'कृपया निम्नलिखित दस्तावेज संलग्न देखें:', pLabel: 'विस्तृत प्रस्ताव', iLabel: 'चालान' }
};
const t = translations[language] || translations['English'];
const budget = parseFloat(String(inputData['Budget / Pricing Agreed'] || '0').replace(/[^0-9.]/g, '')) || 0;
const gstAmount = Math.round(budget * 0.18 * 100) / 100;
const totalWithGST = budget + gstAmount;
const proposalSuffix = Date.now().toString().slice(-5);
const result = {
  clientName: inputData['Client Full Name'] || 'Valued Client',
  companyName: inputData['Company Name'] || 'Your Company',
  clientEmail: inputData['Client Email'] || '',
  industry: inputData['Industry / Niche'] || 'General',
  serviceType: inputData['Service Requested'] || 'Consulting',
  budget, budgetFormatted: '₹' + budget.toLocaleString('en-IN'),
  gstAmount, gstFormatted: '₹' + gstAmount.toLocaleString('en-IN'),
  totalWithGST, totalFormatted: '₹' + totalWithGST.toLocaleString('en-IN'),
  timeline: inputData['Timeline'] || '4-6 weeks',
  goals: inputData['Key Goals / Requirements'] || '',
  notes: inputData['Additional Notes'] || 'None',
  language,
  proposalId: 'PROP-' + proposalSuffix,
  invoiceId: 'INV-' + proposalSuffix,
  dateCreated: new Date().toLocaleDateString('en-IN', { year: 'numeric', month: 'long', day: 'numeric' }),
  dueDate: new Date(Date.now() + 15 * 86400000).toLocaleDateString('en-IN', { year: 'numeric', month: 'long', day: 'numeric' }),
  emailSubject: t.subject + ' — ' + (inputData['Company Name'] || 'Your Company'),
  emailGreeting: t.greeting,
  emailSummary: t.summary,
  emailAttached: t.attached,
  pLabel: t.pLabel,
  iLabel: t.iLabel,
  acceptUrl: 'https://n8n.pureremedysolutions.com/webhook/proposal-accept?proposalId=PROP-' + proposalSuffix,
  declineUrl: 'https://n8n.pureremedysolutions.com/webhook/proposal-decline?proposalId=PROP-' + proposalSuffix
};
const langInstr = language !== 'English' ? '\n\nIMPORTANT: Write ALL proposal content in ' + language + '. Keep technical terms and currency in English.' : '';
result.systemPrompt = 'You are an expert proposal writer. Respond with ONLY a valid JSON object.' + langInstr;
result.userPrompt = 'Create a detailed business proposal JSON for ' + result.companyName + '. Industry: ' + result.industry + '. Service: ' + result.serviceType + '. Budget: ₹' + budget + '. Timeline: ' + result.timeline + '. Goals: ' + result.goals + '. Return JSON with keys: executive_summary, why_choose_us, our_approach, scope_of_work, deliverables_timeline, expected_outcomes, investment_justification, competitive_positioning.';
return [{ json: result }];

const aiResponse = $input.first().json;
const formData = $('🔧 Parse & Prepare').first().json;

let aiContent;
try {
  let raw = '';
  if (aiResponse.message && aiResponse.message.content) {
    raw = aiResponse.message.content;
  } else if (aiResponse.choices && aiResponse.choices[0]) {
    raw = aiResponse.choices[0].message.content;
  } else if (aiResponse.text) {
    raw = aiResponse.text;
  } else if (typeof aiResponse.content === 'string') {
    raw = aiResponse.content;
  } else if (typeof aiResponse === 'string') {
    raw = aiResponse;
  } else {
    raw = JSON.stringify(aiResponse);
  }
  raw = raw.replace(/```json\s*/gi, '').replace(/```\s*/gi, '').trim();
  const firstBrace = raw.indexOf('{');
  const lastBrace = raw.lastIndexOf('}');
  if (firstBrace !== -1 && lastBrace !== -1) {
    raw = raw.substring(firstBrace, lastBrace + 1);
  }
  aiContent = JSON.parse(raw);
} catch (e) {
  aiContent = {
    executive_summary: `We are excited to present this tailored proposal for ${formData.companyName}. With deep expertise in the ${formData.industry} sector, our team has designed a ${formData.serviceType} engagement built around your specific goals: ${formData.goals}. We are confident this partnership will deliver measurable results within ${formData.timeline}, positioning ${formData.companyName} for accelerated growth.`,
    why_choose_us: `1. Industry Expertise: Our team has delivered 50+ successful ${formData.industry} projects.\n2. Proven Methodology: Our structured approach has achieved an average 35% improvement in client KPIs.\n3. Dedicated Support: A named project manager and weekly progress reviews.\n4. Results Guarantee: We tie our deliverables to measurable outcomes.`,
    our_approach: `Phase 1 — Discovery (Week 1): Audit of ${formData.companyName}'s current state.\nPhase 2 — Strategy (Week 2): Data-driven roadmap development.\nPhase 3 — Execution (Week 3 onward)`
  };
}
return [{ json: { ...formData, ...aiContent } }];

const items = $input.all();
for (const item of items) {
  if (item.binary && item.binary.data) {
    item.binary.proposalPDF = item.binary.data;
    delete item.binary.data;
  }
}
return items;

const items = $input.all();
for (const item of items) {
  if (item.binary && item.binary.data) {
    item.binary.invoicePDF = item.binary.data;
    delete item.binary.data;
  }
}
return items;

const items = $input.all();
let proposalBinary = null, invoiceBinary = null, merged = {};
for (const item of items) {
  merged = { ...merged, ...item.json };
  if (item.binary) {
    if (item.binary.proposalPDF) proposalBinary = item.binary.proposalPDF;
    if (item.binary.invoicePDF) invoiceBinary = item.binary.invoicePDF;
  }
}
const output = { json: merged, binary: {} };
if (proposalBinary) output.binary.proposalPDF = proposalBinary;
if (invoiceBinary) output.binary.invoicePDF = invoiceBinary;
return [output];

const d = $('🔀 Merge AI + Form Data').first().json;
const msg = `📤 *Proposal Sent*

👤 *Client:* ${d.clientName}
🏢 *Company:* ${d.companyName}
📧 *Email:* ${d.clientEmail}
🛠 *Service:* ${d.serviceType}
💰 *Value:* ${d.totalFormatted}
🆔 *Proposal:* ${d.proposalId}`;
return [{ json: { ...d, text: msg } }];

const proposalId = $('✅ Webhook Accept').first().json.query?.proposalId || '';
const sheetData = $('🔍 Read CRM Accept').first().json;
const rows = sheetData.values || [];
let found = null;
let rowIndex = -1;
for (let i = 1; i < rows.length; i++) {
  if (String(rows[i][0] || '').trim() === proposalId.trim()) {
    found = rows[i];
    rowIndex = i + 1;
    break;
  }
}
if (!found && rows.length > 1) {
  found = rows[rows.length - 1];
  rowIndex = rows.length;
}
const clientName = found ? (found[3] || 'Valued Client') : 'Valued Client';
const companyName = found ? (found[4] || 'Your Company') : 'Your Company';
const clientEmail = found ? (found[5] || '') : '';
const serviceType = found ? (found[6] || 'Consulting') : 'Consulting';
const totalFormatted = found ? (found[9] || '') : '';
return [{ json: { proposalId, rowIndex, clientName, companyName, clientEmail, serviceType, totalFormatted, status: 'Proposal Accepted' } }];

const d = $('⚙️ Process Accept').first().json;
const msg = `🎉 *Proposal ACCEPTED!*

👤 *Client:* ${d.clientName}
🏢 *Company:* ${d.companyName}
📧 *Email:* ${d.clientEmail}
🛠 *Service:* ${d.serviceType}
💰 *Value:* ${d.totalFormatted}
🆔 *Proposal ID:* ${d.proposalId}`;
return [{ json: { text: msg } }];

const proposalId = $('❌ Webhook Decline').first().json.query?.proposalId || '';
const sheetData = $('🔍 Read CRM Decline').first().json;
const rows = sheetData.values || [];
let found = null;
let rowIndex = -1;
for (let i = 1; i < rows.length; i++) {
  if (String(rows[i][0] || '').trim() === proposalId.trim()) {
    found = rows[i];
    rowIndex = i + 1;
    break;
  }
}
if (!found && rows.length > 1) {
  found = rows[rows.length - 1];
  rowIndex = rows.length;
}
const clientName = found ? (found[3] || 'Valued Client') : 'Valued Client';
const companyName = found ? (found[4] || 'Your Company') : 'Your Company';
return [{ json: { proposalId, rowIndex, clientName, companyName, status: 'Proposal Declined' } }];
